@Component
class RedirectUriValidator {

    /**
     * Validates the redirect_uri using EXACT MATCH against registered URIs.
     *
     * Per RFC 6749 Section 3.1.2.2 and OAuth 2.0 Security Best Current Practice (RFC 9700):
     * - The authorization server MUST require exact matching of the redirect URI.
     * - Prefix/substring matching is vulnerable to open redirect attacks.
     *
     * An attacker could register a domain like "app.enterprise.com.evil.com" or use
     * "app.enterprise.com.attacker.com/callback" which would pass a startsWith check
     * but redirect tokens to an attacker-controlled server.
     */
    public boolean isValidRedirectUri(String redirectUri, RegisteredClient client) {
        if (redirectUri == null || redirectUri.isBlank()) {
            return false;
        }

        // Normalize and parse the URI to prevent bypass via encoding tricks
        URI parsedUri;
        try {
            parsedUri = new URI(redirectUri).normalize();
        } catch (URISyntaxException e) {
            return false;
        }

        // Reject URIs with fragments (per RFC 6749 Section 3.1.2)
        if (parsedUri.getFragment() != null) {
            return false;
        }

        // Require HTTPS scheme (except localhost for development)
        String scheme = parsedUri.getScheme();
        if (scheme == null) {
            return false;
        }
        String host = parsedUri.getHost();
        if (host == null) {
            return false;
        }

        boolean isLocalhost = "localhost".equals(host) || "127.0.0.1".equals(host) || "::1".equals(host);
        if (!isLocalhost && !"https".equalsIgnoreCase(scheme)) {
            return false;
        }

        // Reject URIs with userinfo component (e.g., https://attacker@legitimate.com/callback)
        if (parsedUri.getUserInfo() != null) {
            return false;
        }

        // Reconstruct a normalized form for comparison to prevent encoding-based bypasses
        String normalizedRequestUri = normalizeUri(parsedUri);

        // EXACT MATCH against each registered redirect URI
        for (String registeredUri : client.getAllowedRedirectUris()) {
            try {
                URI parsedRegistered = new URI(registeredUri).normalize();
                String normalizedRegistered = normalizeUri(parsedRegistered);
                if (normalizedRequestUri.equals(normalizedRegistered)) {
                    return true;
                }
            } catch (URISyntaxException e) {
                // Skip malformed registered URIs
                continue;
            }
        }

        return false;
    }

    /**
     * Normalizes a URI for safe comparison:
     * - Lowercases scheme and host
     * - Removes default ports
     * - Ensures path has trailing consistency
     */
    private String normalizeUri(URI uri) {
        String scheme = uri.getScheme().toLowerCase();
        String host = uri.getHost().toLowerCase();

        int port = uri.getPort();
        // Remove default ports
        if (("https".equals(scheme) && port == 443) || ("http".equals(scheme) && port == 80)) {
            port = -1;
        }

        String path = uri.getPath();
        if (path == null || path.isEmpty()) {
            path = "/";
        }
        // Remove trailing slash for consistency, except for root path
        if (path.length() > 1 && path.endsWith("/")) {
            path = path.substring(0, path.length() - 1);
        }

        String query = uri.getQuery();

        StringBuilder sb = new StringBuilder();
        sb.append(scheme).append("://").append(host);
        if (port != -1) {
            sb.append(":").append(port);
        }
        sb.append(path);
        if (query != null && !query.isEmpty()) {
            sb.append("?").append(query);
        }
        return sb.toString();
    }

    /**
     * Returns the default redirect URI if only one is registered.
     */
    public Optional<String> getDefaultRedirectUri(RegisteredClient client) {
        Set<String> uris = client.getAllowedRedirectUris();
        if (uris != null && uris.size() == 1) {
            return Optional.of(uris.iterator().next());
        }
        return Optional.empty();
    }
}

