@Service
class AuthorizationCodeStore {
    private static final int CODE_EXPIRATION_MINUTES = 10;
    private static final int CODE_LENGTH_BYTES = 32;

    private final Map<String, AuthorizationCode> codeStore = new ConcurrentHashMap<>();
    private final SecureRandom secureRandom = new SecureRandom();

    public AuthorizationCode generateCode(String clientId, String redirectUri, String userId, Set<String> scopes) {
        // Clean up expired codes periodically
        cleanupExpiredCodes();

        String code = generateSecureCode();
        Instant expiresAt = Instant.now().plusSeconds(CODE_EXPIRATION_MINUTES * 60L);

        AuthorizationCode authCode = new AuthorizationCode(code, clientId, redirectUri, userId, scopes, expiresAt);
        codeStore.put(code, authCode);

        return authCode;
    }

    public Optional<AuthorizationCode> consumeCode(String code) {
        if (code == null) return Optional.empty();

        AuthorizationCode authCode = codeStore.remove(code);
        if (authCode == null) {
            return Optional.empty();
        }

        if (authCode.isExpired()) {
            return Optional.empty();
        }

        if (authCode.isUsed()) {
            // Code reuse attempt - potential attack, invalidate all codes for this client
            revokeAllCodesForClient(authCode.getClientId());
            return Optional.empty();
        }

        authCode.setUsed(true);
        return Optional.of(authCode);
    }

    private void revokeAllCodesForClient(String clientId) {
        codeStore.entrySet().removeIf(entry -> entry.getValue().getClientId().equals(clientId));
    }

    private void cleanupExpiredCodes() {
        codeStore.entrySet().removeIf(entry -> entry.getValue().isExpired());
    }

    private String generateSecureCode() {
        byte[] bytes = new byte[CODE_LENGTH_BYTES];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    public int getActiveCodeCount() {
        cleanupExpiredCodes();
        return codeStore.size();
    }
}

// --- Scope Validator ---

@Component
class ScopeValidator {
    public Set<String> validateScopes(String requestedScopes, RegisteredClient client) {
        if (requestedScopes == null || requestedScopes.isBlank()) {
            // Return default scopes (e.g., "read")
            return Set.of("read");
        }

        Set<String> requested = Arrays.stream(requestedScopes.split("\\s+"))
            .map(String::trim)
            .filter(s -> !s.isEmpty())
            .collect(Collectors.toSet());

        Set<String> allowed = client.getAllowedScopes();
        Set<String> validated = new LinkedHashSet<>();

        for (String scope : requested) {
            if (allowed.contains(scope)) {
                validated.add(scope);
            }
        }

        if (validated.isEmpty()) {
            return Set.of("read"); // Fallback to minimal scope
        }

        return validated;
    }
}

