@Component
class CsrfTokenManager {
    private final SecureRandom secureRandom = new SecureRandom();

    public String generateToken() {
        byte[] bytes = new byte[32];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    public boolean validateToken(String sessionToken, String requestToken) {
        if (sessionToken == null || requestToken == null) return false;
        // Constant-time comparison to prevent timing attacks
        return java.security.MessageDigest.isEqual(
            sessionToken.getBytes(java.nio.charset.StandardCharsets.UTF_8),
            requestToken.getBytes(java.nio.charset.StandardCharsets.UTF_8)
        );
    }
}

