@RestController
@RequestMapping("/oauth")
class AuthorizationController {

    private final ClientRegistryService clientRegistry;
    private final RedirectUriValidator redirectUriValidator;
    private final AuthorizationCodeStore codeStore;
    private final ScopeValidator scopeValidator;
    private final CsrfTokenManager csrfTokenManager;

    public AuthorizationController(ClientRegistryService clientRegistry,
                                    RedirectUriValidator redirectUriValidator,
                                    AuthorizationCodeStore codeStore,
                                    ScopeValidator scopeValidator,
                                    CsrfTokenManager csrfTokenManager) {
        this.clientRegistry = clientRegistry;
        this.redirectUriValidator = redirectUriValidator;
        this.codeStore = codeStore;
        this.scopeValidator = scopeValidator;
        this.csrfTokenManager = csrfTokenManager;
    }

    /**
     * Authorization endpoint - GET request to initiate authorization flow.
     * Displays consent page to the user.
     */
    @GetMapping("/authorize")
    public ResponseEntity<?> authorize(
            @RequestParam(value = "response_type", required = false) String responseType,
            @RequestParam(value = "client_id", required = false) String clientId,
            @RequestParam(value = "redirect_uri", required = false) String redirectUri,
            @RequestParam(value = "scope", required = false) String scope,
            @RequestParam(value = "state", required = false) String state,
            HttpServletRequest request,
            HttpSession session) {

        // Validate response_type
        if (!"code".equals(responseType)) {
            return ResponseEntity.badRequest().body(
                new OAuthError("unsupported_response_type", "Only 'code' response type is supported")
            );
        }

        // Validate client_id
        if (clientId == null || clientId.isBlank()) {
            return ResponseEntity.badRequest().body(
                new OAuthError("invalid_request", "client_id is required")
            );
        }

        Optional<RegisteredClient> clientOpt = clientRegistry.findByClientId(clientId);
        if (clientOpt.isEmpty()) {
            return ResponseEntity.badRequest().body(
                new OAuthError("invalid_client", "Unknown client_id")
            );
        }

        RegisteredClient client = clientOpt.get();

        // Validate redirect_uri - EXACT MATCH (secure implementation)
        String effectiveRedirectUri = redirectUri;
        if (effectiveRedirectUri == null || effectiveRedirectUri.isBlank()) {
            // If not provided, use default only if exactly one is registered
            Optional<String> defaultUri = redirectUriValidator.getDefaultRedirectUri(client);
            if (defaultUri.isPresent()) {
                effectiveRedirectUri = defaultUri.get();
            } else {
                return ResponseEntity.badRequest().body(
                    new OAuthError("invalid_request", "redirect_uri is required when multiple URIs are registered")
                );
            }
        }

        if (!redirectUriValidator.isValidRedirectUri(effectiveRedirectUri, client)) {
            // Do NOT redirect to the unvalidated URI - return error directly
            return ResponseEntity.badRequest().body(
                new OAuthError("invalid_redirect_uri",
                    "The provided redirect_uri does not exactly match any registered redirect URI for this client")
            );
        }

        // Validate scopes
        Set<String> validatedScopes = scopeValidator.validateScopes(scope, client);

        // Generate CSRF token for the consent form
        String csrfToken = csrfTokenManager.generateToken();
        session.setAttribute("oauth_csrf_token", csrfToken);
        session.setAttribute("oauth_client_id", clientId);
        session.setAttribute("oauth_redirect_uri", effectiveRedirectUri);
        session.setAttribute("oauth_scopes", String.join(" ", validatedScopes));
        session.setAttribute("oauth_state", state);

        // Return consent page data (in production, render an HTML template)
        Map<String, Object> consentData = new LinkedHashMap<>();
        consentData.put("clientName", client.getClientName());
        consentData.put("clientId", clientId);
        consentData.put("requestedScopes", validatedScopes);
        consentData.put("csrfToken", csrfToken);
        consentData.put("consentUrl", "/oauth/authorize/consent");

        return ResponseEntity.ok(consentData);
    }

    /**
     * Consent submission endpoint - POST request after user approves/denies.
     */
    @PostMapping("/authorize/consent")
    public void handleConsent(
            @RequestParam(value = "csrf_token", required = false) String csrfToken,
            @RequestParam(value = "approved", required = false, defaultValue = "false") boolean approved,
            HttpSession session,
            HttpServletResponse response) throws IOException {

        // Validate CSRF token
        String sessionCsrf = (String) session.getAttribute("oauth_csrf_token");
        if (!csrfTokenManager.validateToken(sessionCsrf, csrfToken)) {
            response.sendError(HttpStatus.FORBIDDEN.value(), "Invalid CSRF token");
            return;
        }

        String clientId = (String) session.getAttribute("oauth_client_id");
        String redirectUri = (String) session.getAttribute("oauth_redirect_uri");
        String scopes = (String) session.getAttribute("oauth_scopes");
        String state = (String) session.getAttribute("oauth_state");

        // Clear session attributes
        session.removeAttribute("oauth_csrf_token");
        session.removeAttribute("oauth_client_id");
        session.removeAttribute("oauth_redirect_uri");
        session.removeAttribute("oauth_scopes");
        session.removeAttribute("oauth_state");

        if (clientId == null || redirectUri == null) {
            response.sendError(HttpStatus.BAD_REQUEST.value(), "Invalid session state");
            return;
        }

        // Re-validate the redirect URI before redirecting (defense in depth)
        Optional<RegisteredClient> clientOpt = clientRegistry.findByClientId(clientId);
        if (clientOpt.isEmpty() || !redirectUriValidator.isValidRedirectUri(redirectUri, clientOpt.get())) {
            response.sendError(HttpStatus.BAD_REQUEST.value(), "Invalid redirect URI");
            return;
        }

        if (!approved) {
            // User denied - redirect with error
            String denyRedirect = buildRedirectUri(redirectUri, Map.of(
                "error", "access_denied",
                "error_description", "The user denied the authorization request"
            ), state);
            response.sendRedirect(denyRedirect);
            return;
        }

        // User approved - generate authorization code
        // In production, get userId from authenticated session/security context
        String userId = getAuthenticatedUserId(session);
        if (userId == null) {
            response.sendError(HttpStatus.UNAUTHORIZED.value(), "User not authenticated");
            return;
        }

        Set<String> scopeSet = Arrays.stream(scopes.split("\\s+"))
            .collect(Collectors.toSet());

        AuthorizationCode authCode = codeStore.generateCode(clientId, redirectUri, userId, scopeSet);

        String approveRedirect = buildRedirectUri(redirectUri, Map.of(
            "code", authCode.getCode()
        ), state);

        response.sendRedirect(approveRedirect);
    }

    /**
     * Token endpoint - Exchange authorization code for tokens.
     */
    @PostMapping("/token")
    public ResponseEntity<?> token(
            @RequestParam(value = "grant_type", required = false) String grantType,
            @RequestParam(value = "code", required = false) String code,
            @RequestParam(value = "redirect_uri", required = false) String redirectUri,
            @RequestParam(value = "client_id", required = false) String clientId,
            @RequestParam(value = "client_secret", required = false) String clientSecret) {

        if (!"authorization_code".equals(grantType)) {
            return ResponseEntity.badRequest().body(
                new OAuthError("unsupported_grant_type", "Only 'authorization_code' grant type is supported")
            );
        }

        if (code == null || code.isBlank()) {
            return ResponseEntity.badRequest().body(
                new OAuthError("invalid_request", "Authorization code is required")
            );
        }

        // Consume the code (one-time use)
        Optional<AuthorizationCode> authCodeOpt = codeStore.consumeCode(code);
        if (authCodeOpt.isEmpty()) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(
                new OAuthError("invalid_grant", "Authorization code is invalid, expired, or already used")
            );
        }

        AuthorizationCode authCode = authCodeOpt.get();

        // Validate client credentials
        if (!authCode.getClientId().equals(clientId)) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(
                new OAuthError("invalid_client", "Client authentication failed")
            );
        }

        Optional<RegisteredClient> clientOpt = clientRegistry.findByClientId(clientId);
        if (clientOpt.isEmpty()) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(
                new OAuthError("invalid_client", "Unknown client")
            );
        }

        // In production, verify client_secret using BCrypt
        // For this example, we do a basic check
        if (clientSecret == null || clientSecret.isBlank()) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(
                new OAuthError("invalid_client", "Client secret is required")
            );
        }

        // Validate redirect_uri matches the one used during authorization
        if (redirectUri != null && !redirectUri.equals(authCode.getRedirectUri())) {
            return ResponseEntity.badRequest().body(
                new OAuthError("invalid_grant", "redirect_uri does not match the one used during authorization")
            );
        }

        // Generate tokens (simplified - in production use JWT with proper signing)
        Map<String, Object> tokenResponse = new LinkedHashMap<>();
        tokenResponse.put("access_token", generateAccessToken());
        tokenResponse.put("token_type", "Bearer");
        tokenResponse.put("expires_in", 3600);
        tokenResponse.put("scope", String.join(" ", authCode.getScopes()));
        tokenResponse.put("refresh_token", generateRefreshToken());

        return ResponseEntity.ok(tokenResponse);
    }

    // --- Helper Methods ---

    private String buildRedirectUri(String baseUri, Map<String, String> params, String state) {
        StringBuilder sb = new StringBuilder(baseUri);
        sb.append(baseUri.contains("?") ? "&" : "?");

        List<String> queryParams = new ArrayList<>();
        for (Map.Entry<String, String> entry : params.entrySet()) {
            queryParams.add(urlEncode(entry.getKey()) + "=" + urlEncode(entry.getValue()));
        }
        if (state != null && !state.isBlank()) {
            queryParams.add("state=" + urlEncode(state));
        }

        sb.append(String.join("&", queryParams));
        return sb.toString();
    }

    private String urlEncode(String value) {
        try {
            return java.net.URLEncoder.encode(value, java.nio.charset.StandardCharsets.UTF_8);
        } catch (Exception e) {
            return value;
        }
    }

    private String getAuthenticatedUserId(HttpSession session) {
        // In production, integrate with Spring Security's SecurityContextHolder
        String userId = (String) session.getAttribute("authenticated_user_id");
        if (userId == null) {
            // For demo purposes, return a placeholder
            userId = "demo-user-001";
        }
        return userId;
    }

    private String generateAccessToken() {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private String generateRefreshToken() {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }
}

